query:
CREATE TABLE IF NOT EXISTS `contracts` (`id` int AUTO_INCREMENT NOT NULL, `title` varchar(255) NOT NULL, `contactId` int, `leadId` int, `assignedUserId` int, `status` enum('draft','sent','signed','cancelled') DEFAULT 'draft', `content` text, `value` decimal(12,2), `currency` varchar(8) DEFAULT 'BRL', `signedAt` timestamp, `signatoryName` varchar(255), `signatoryEmail` varchar(320), `expiresAt` timestamp, `fileUrl` text, `signatureUrl` text, `notes` text, `createdAt` timestamp NOT NULL DEFAULT (now()), `updatedAt` timestamp NOT NULL DEFAULT (now()) ON UPDATE CURRENT_TIMESTAMP, CONSTRAINT `contracts_id` PRIMARY KEY(`id`));

CREATE TABLE IF NOT EXISTS `invoices` (`id` int AUTO_INCREMENT NOT NULL, `number` varchar(64) NOT NULL, `contactId` int, `leadId` int, `assignedUserId` int, `status` enum('draft','sent','paid','overdue','cancelled') DEFAULT 'draft', `items` json, `subtotal` decimal(12,2), `tax` decimal(12,2) DEFAULT '0', `total` decimal(12,2), `currency` varchar(8) DEFAULT 'BRL', `dueDate` timestamp, `paidAt` timestamp, `stripePaymentIntentId` varchar(255), `stripePaymentUrl` text, `fileUrl` text, `notes` text, `createdAt` timestamp NOT NULL DEFAULT (now()), `updatedAt` timestamp NOT NULL DEFAULT (now()) ON UPDATE CURRENT_TIMESTAMP, CONSTRAINT `invoices_id` PRIMARY KEY(`id`), CONSTRAINT `invoices_number_unique` UNIQUE(`number`));

CREATE TABLE IF NOT EXISTS `quotes` (`id` int AUTO_INCREMENT NOT NULL, `number` varchar(64) NOT NULL, `contactId` int, `leadId` int, `assignedUserId` int, `status` enum('draft','sent','accepted','rejected','expired') DEFAULT 'draft', `items` json, `subtotal` decimal(12,2), `discount` decimal(12,2) DEFAULT '0', `tax` decimal(12,2) DEFAULT '0', `total` decimal(12,2), `currency` varchar(8) DEFAULT 'BRL', `validUntil` timestamp, `fileUrl` text, `notes` text, `createdAt` timestamp NOT NULL DEFAULT (now()), `updatedAt` timestamp NOT NULL DEFAULT (now()) ON UPDATE CURRENT_TIMESTAMP, CONSTRAINT `quotes_id` PRIMARY KEY(`id`), CONSTRAINT `quotes_number_unique` UNIQUE(`number`));

